export type ScenarioInput = {
  customer: { yearsWithMHPCO: number };
  steps: Array<{
    op: string;
    items?: Array<{
      type: string;
      material?: string;
      enchantment?: number;
      cursed?: boolean;
    }>;
    policy?: number;
    incident?: {
      cause: string;
      damages: Array<{
        itemType: string;
        amount: number;
      }>;
    };
  }>;
};

export type ScenarioResult = {
  results: Array<{ premium: number } | { payout: number; remainingCap: number }>;
};

export function processScenario(_input: ScenarioInput): ScenarioResult {
  return { results: [] };
}

