      }>;
    };
  }>;
};

export type ScenarioResult = {
  results: Array<{ premium: number } | { payout: number; remainingCap: number }>;
};

function calculateQuotePremium(items: ItemInput[]): number {
  if (items.length === 0) {
    return PROCESSING_FEE;
  }
  const base = BASE_PREMIUMS[items[0].type];
  return Math.ceil(base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE);
}

export function processScenario(input: ScenarioInput): ScenarioResult {
  const results: ScenarioResult["results"] = [];
  for (const step of input.steps) {
    if (step.op === "quote") {
      const items = step.items ?? [];
      results.push({ premium: calculateQuotePremium(items) });
    }
  }
  return { results };
}

