function calculateQuotePremium(items: ItemInput[]): number {
  if (items.length === 0) {
    return PROCESSING_FEE;
  }
  let basePremium = 0;
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      basePremium += BASE_PREMIUMS[item.type];
    }
  }
  for (const [type, count] of Object.entries(componentCounts)) {
    if (count === 3) {
      basePremium += BLOCK_PREMIUM;
    } else {
      basePremium += count * COMPONENT_PREMIUM;
    }
  }
  return Math.ceil(basePremium + basePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE);
}

